// \u9802\u70B9\u30B7\u30A7\u30FC\u30C0\u30FC\u306B\u5165\u529B\u3055\u308C\u308B attribute \u5909\u6570
//attribute vec4 position;       //!< \u5165\u529B: \u4F4D\u7F6E\u60C5\u5831
